args.query:
SELECT oi.Id AS OrderItemId, oi.Product2Id, ord.EffectiveDate
FROM "Order" ord
JOIN OrderItem oi ON oi.OrderId = ord.Id
WHERE REPLACE(ord.AccountId, '#', '') IN (
  SELECT REPLACE(AccountId, '#', '') FROM core_crm.Contact WHERE REPLACE(Id, '#', '') = REPLACE('003Wt00000Jqy8SIAR', '#', '')
);

